21	#[derive(Debug)]
22	pub(crate) struct UdtRcvQueue {
23	    sockets: Mutex<VecDeque<(Instant, SocketId)>>,
24	    mss: u32,
25	    channel: Arc<UdpSocket>,
26	    multiplexer: Mutex<Weak<UdtMultiplexer>>,
27	    socket_refs: Mutex<BTreeMap<SocketId, Weak<UdtSocket>>>,
28	}
29	
30	impl UdtRcvQueue {
31	    pub fn new(channel: Arc<UdpSocket>, mss: u32) -> Self {
32	        Self {
33	            sockets: Mutex::new(VecDeque::new()),
34	            mss,
35	            channel,
36	            multiplexer: Mutex::new(Weak::new()),
37	            socket_refs: Mutex::new(BTreeMap::new()),
38	        }
39	    }
40	
41	    pub fn push_back(&self, socket_id: SocketId) {
42	        self.sockets
43	            .lock()
44	            .unwrap()
45	            .push_back((Instant::now(), socket_id));
46	    }
47	
48	    fn update(&self, socket_id: SocketId) {
49	        let mut queue = self.sockets.lock().unwrap();
50	        queue.retain(|(_, id)| socket_id != *id);
51	        queue.push_back((Instant::now(), socket_id));
52	    }
53	
54	    pub fn set_multiplexer(&self, mux: &Arc<UdtMultiplexer>) {
55	        *self.multiplexer.lock().unwrap() = Arc::downgrade(mux);
56	    }
57	
58	    async fn get_socket(&self, socket_id: SocketId) -> Option<SocketRef> {
59	        let known_socket = self.socket_refs.lock().unwrap().get(&socket_id).cloned();
60	        if let Some(socket) = known_socket {
61	            socket.upgrade()
62	        } else if let Some(socket) = Udt::get().read().await.get_socket(socket_id) {
63	            self.socket_refs
64	                .lock()
65	                .unwrap()
66	                .insert(socket_id, Arc::downgrade(&socket));
67	            Some(socket)
68	        } else {
69	            None
70	        }
71	    }
72	
73	    #[cfg(target_os = "linux")]
74	    fn receive_packets(&self, buf: &mut [u8]) -> Result<Vec<(usize, SocketAddr)>> {
75	        use nix::sys::socket::{
76	            recvmmsg, AddressFamily, MsgFlags, RecvMmsgData, SockaddrLike, SockaddrStorage,
77	        };
78	        use std::io::IoSliceMut;
79	        use std::os::unix::io::AsRawFd;
80	        use tokio::io::Interest;
81	        let bufs = buf.chunks_exact_mut(self.mss as usize);
82	        let mut recv_mesg_data: Vec<RecvMmsgData<_>> = bufs
83	            .map(|b| RecvMmsgData {
84	                iov: [IoSliceMut::new(&mut b[..])],
85	                cmsg_buffer: None,
86	            })
87	            .collect();
88	
89	        self.channel.try_io(Interest::READABLE, || {
90	            let msgs = recvmmsg(
91	                self.channel.as_raw_fd(),
92	                &mut recv_mesg_data,
93	                MsgFlags::MSG_DONTWAIT,
94	                None,
95	            )
96	            .map_err(|err| {
97	                if err == nix::errno::Errno::EWOULDBLOCK {
98	                    return Error::new(ErrorKind::WouldBlock, "recvmmsg would block");
99	                }
100	                Error::new(ErrorKind::Other, err)
101	            })?
102	            .iter()
103	            .map(|msg| {
